import{_ as a,o as d,c as e,a2 as s}from"./chunks/framework.BWuWLRhz.js";const b=JSON.parse('{"title":"股民保护 BI 看板","description":"","frontmatter":{},"headers":[],"relativePath":"projects/liduoxing/woodpecker-bi.md","filePath":"projects/liduoxing/woodpecker-bi.md"}'),n={name:"projects/liduoxing/woodpecker-bi.md"};function l(i,t,r,o,p,h){return d(),e("div",null,[...t[0]||(t[0]=[s(`<h1 id="股民保护-bi-看板" tabindex="-1">股民保护 BI 看板 <a class="header-anchor" href="#股民保护-bi-看板" aria-label="Permalink to &quot;股民保护 BI 看板&quot;">​</a></h1><blockquote><p>股民保护 BI 看板是围绕投资者权益维护业务搭建的数据产品项目。它把 <span class="text-highlight-blue">公域曝光、资源进线、私域咨询、客户分类、签约转化、维权标的和法务流程</span> 组织成一条可追踪的数据链路，帮助业务从手工报表升级为可复盘的经营看板。</p></blockquote><div class="project-snapshot"><div><strong>2025 年启动</strong><span>股民保护与投资者权益维护业务项目</span></div><div><strong>渠道漏斗</strong><span>公域曝光、私域进线、咨询、签约、立案</span></div><div><strong>看板原型</strong><span>总览、渠道、运营多类 dashboard demo</span></div><div><strong>数据口径</strong><span>资源、A 类客户、维权股、标的金额、营收估算</span></div></div><h2 id="项目背景" tabindex="-1">项目背景 <a class="header-anchor" href="#项目背景" aria-label="Permalink to &quot;项目背景&quot;">​</a></h2><p>股民保护项目围绕投资者权益维护业务展开，业务通过公域内容、视频号、公众号、私域 H5、客服咨询和法务流程承接潜在客户。</p><p>早期数据主要依赖人工维护和定期汇报，管理层难以持续追踪：</p><ul><li>公域账号带来了多少曝光和粉丝？</li><li>哪些渠道带来的资源更有效？</li><li>客户从私信咨询到签约转化的路径是什么？</li><li>哪些客户符合维权条件？</li><li>哪些维权标的贡献了主要签约和金额？</li><li>手工报表中的资源数、A 类客户、营收估算等口径是否统一？</li></ul><p>因此，项目需要将业务流程线上化、指标化和看板化。</p><h2 id="项目目标" tabindex="-1">项目目标 <a class="header-anchor" href="#项目目标" aria-label="Permalink to &quot;项目目标&quot;">​</a></h2><ol><li>梳理股民保护业务流程，从公域曝光到签约和后续维权形成完整路径。</li><li>明确资源、客户分类、维权股、标的金额、营收估算等关键口径。</li><li>建立管理层驾驶舱和运营看板，持续追踪渠道效率和签约转化。</li><li>将人工报表和业务经验转化为可开发、可验收的数据产品需求。</li><li>为后续线上化和自动化采集打基础。</li></ol><h2 id="我的角色" tabindex="-1">我的角色 <a class="header-anchor" href="#我的角色" aria-label="Permalink to &quot;我的角色&quot;">​</a></h2><p>我负责业务理解、流程图梳理、数据源口径整理、BI 看板需求和原型 demo 推进。这个项目的重点，是先理解业务方真正想追踪的路径，再把报表拆成可开发的数据对象。</p><table tabindex="0"><thead><tr><th>工作方向</th><th>我承担的工作</th></tr></thead><tbody><tr><td>业务梳理</td><td>理解公域账号、私域咨询、客服承接、客户分类、签约和法务流程</td></tr><tr><td>口径确认</td><td>梳理资源数、A 类客户、维权股、标的金额、营收估算等概念</td></tr><tr><td>流程设计</td><td>绘制客户从渠道进入、咨询、判断、签约到后续处理的路径</td></tr><tr><td>看板设计</td><td>设计总览、渠道、运营、签约、标的等看板模块</td></tr><tr><td>原型推进</td><td>用 HTML demo / 墨刀原型 / BI 报表方式快速验证展示结构</td></tr></tbody></table><h2 id="业务数据链路" tabindex="-1">业务数据链路 <a class="header-anchor" href="#业务数据链路" aria-label="Permalink to &quot;业务数据链路&quot;">​</a></h2><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>公域曝光</span></span>
<span class="line"><span>  -&gt; 资源进线</span></span>
<span class="line"><span>  -&gt; 私域咨询</span></span>
<span class="line"><span>  -&gt; 客户分类</span></span>
<span class="line"><span>  -&gt; 签约转化</span></span>
<span class="line"><span>  -&gt; 维权标的</span></span>
<span class="line"><span>  -&gt; 法务处理 / 结果复盘</span></span></code></pre></div><table tabindex="0"><thead><tr><th>环节</th><th>数据对象</th><th>分析价值</th></tr></thead><tbody><tr><td>公域曝光</td><td>视频号、公众号、账号矩阵、曝光量、粉丝数</td><td>判断内容和账号矩阵带来多少流量</td></tr><tr><td>资源进线</td><td>渠道、私信、H5 登记、客服承接</td><td>判断不同渠道的资源质量</td></tr><tr><td>客户咨询</td><td>客户诉求、维权股票、损失情况、是否符合条件</td><td>判断是否值得继续跟进</td></tr><tr><td>客户分类</td><td>A 类客户、潜在客户、意向客户、风险客户</td><td>支持资源优先级分配</td></tr><tr><td>签约转化</td><td>签约数量、签约金额、月度趋势</td><td>判断业务转化效率</td></tr><tr><td>维权标的</td><td>股票标的、维权金额、TOP 标的</td><td>判断业务重点和资源集中度</td></tr></tbody></table><h2 id="看板模块" tabindex="-1">看板模块 <a class="header-anchor" href="#看板模块" aria-label="Permalink to &quot;看板模块&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模块</th><th>核心指标</th><th>业务问题</th></tr></thead><tbody><tr><td>总览驾驶舱</td><td>公域粉丝、客户承载、签约数量、立案数量、维权金额</td><td>业务整体规模和结果如何</td></tr><tr><td>渠道分析</td><td>进线渠道、渠道占比、月度趋势、私域资源</td><td>哪些渠道质量更高</td></tr><tr><td>公域分析</td><td>曝光量、账号矩阵、视频号数据、微信平台数据</td><td>公域内容是否带来有效资源</td></tr><tr><td>转化漏斗</td><td>曝光、进线、咨询、签约、立案</td><td>客户在哪个环节流失</td></tr><tr><td>标的分析</td><td>TOP 维权标的、签约数量、维权总额</td><td>哪些标的贡献主要业务</td></tr><tr><td>运营复盘</td><td>客户净增、签约趋势、维权金额趋势</td><td>月度经营表现如何</td></tr></tbody></table><h2 id="交付成果" tabindex="-1">交付成果 <a class="header-anchor" href="#交付成果" aria-label="Permalink to &quot;交付成果&quot;">​</a></h2><div class="insight-card"><span class="label">项目结果</span><p>交付股民保护 BI 看板，覆盖总览驾驶舱、渠道分析、转化漏斗等 3 个核心模块，梳理从公域曝光到签约转化的完整数据链路，明确资源、A 类客户、维权股、标的金额等关键口径。使用方为业务负责人和产品运营主管，替代原有手工维护报表，从需求梳理到看板上线约 2 周完成。</p></div><h2 id="业务流程与看板结构" tabindex="-1">业务流程与看板结构 <a class="header-anchor" href="#业务流程与看板结构" aria-label="Permalink to &quot;业务流程与看板结构&quot;">​</a></h2><div class="”evidence-callout”"><span class="”label”">关于看板截图</span><p>BI 看板涉及渠道营收、签约金额、客户转化等敏感业务数据，公开作品集不展示原始截图。以上”看板模块”表格已完整说明各模块结构、核心指标和业务价值；如需进一步了解看板设计细节，欢迎面试时沟通。</p></div><h2 id="数据口径难点" tabindex="-1">数据口径难点 <a class="header-anchor" href="#数据口径难点" aria-label="Permalink to &quot;数据口径难点&quot;">​</a></h2><table tabindex="0"><thead><tr><th>口径</th><th>难点</th><th>处理思路</th></tr></thead><tbody><tr><td>资源数</td><td>是渠道进线、咨询客户还是客服承接客户</td><td>明确定义进入看板的资源口径</td></tr><tr><td>A 类客户</td><td>符合维权条件且损失达到一定标准</td><td>将业务判断转成可记录标签</td></tr><tr><td>维权股</td><td>股票背后对应的维权标的公司</td><td>与客户咨询和签约记录建立关联</td></tr><tr><td>风险标签</td><td>来源于风控系统或业务判断</td><td>与公司统一风险标签保持一致</td></tr><tr><td>标的金额</td><td>律师用于法院材料的金额，与损失金额存在换算</td><td>在看板中说明口径来源</td></tr><tr><td>营收估算</td><td>部分阶段为预估值，不等同实际收入</td><td>区分预估金额和实际金额</td></tr></tbody></table><h2 id="数据如何驱动" tabindex="-1">数据如何驱动 <a class="header-anchor" href="#数据如何驱动" aria-label="Permalink to &quot;数据如何驱动&quot;">​</a></h2><p>股民保护 BI 的价值，是让业务从“报一个总数”变成“看清一条路径”。</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>渠道来源</span></span>
<span class="line"><span>  -&gt; 资源质量</span></span>
<span class="line"><span>  -&gt; 客户分类</span></span>
<span class="line"><span>  -&gt; 签约效率</span></span>
<span class="line"><span>  -&gt; 标的贡献</span></span>
<span class="line"><span>  -&gt; 经营复盘</span></span></code></pre></div><p>如果某个月签约下降，看板可以继续下钻：是公域曝光下降、进线资源减少、客服承接不足、A 类客户比例下降，还是某些维权标的转化变差。</p><h2 id="成果与价值" tabindex="-1">成果与价值 <a class="header-anchor" href="#成果与价值" aria-label="Permalink to &quot;成果与价值&quot;">​</a></h2><ul><li>梳理股民保护业务背景、核心角色、客户路径和数据口径。</li><li>输出业务流程图、数据来源口径表、看板字段清单和 BI 需求文档。</li><li>建立总览、渠道、运营等 dashboard demo，帮助业务快速对齐展示方向。</li><li>将手工报表转化为可线上化的数据产品需求。</li><li>为后续自动采集、客户标签和渠道复盘打基础。</li></ul><h2 id="个人能力沉淀" tabindex="-1">个人能力沉淀 <a class="header-anchor" href="#个人能力沉淀" aria-label="Permalink to &quot;个人能力沉淀&quot;">​</a></h2><p>这个项目让我再次确认，BI 看板要先理解业务路径，再把数据按路径组织起来。只有知道客户从哪里来、为什么转化、在哪里流失，看板才真正有管理价值。</p>`,32)])])}const u=a(n,[["render",l]]);export{b as __pageData,u as default};
